Bash(powershell -Command "
\\$file = 'D:\\mannshaft\\build\\test-results\\test\\binary\\output.bin'
if \(Test-Path \\$file\) {
    try {
        \\$handle = [System.IO.File]::Open\(\\$file, [System.IO.FileMode]::Open, [System.IO.FileAccess]::ReadWrite, [System.IO.FileShare]::None\)
        \\$handle.Close\(\)
        Write-Host 'File is not locked'
    } catch {
        Write-Host 'File IS locked: ' + \\$_.Exception.Message
    }
} else {
    Write-Host 'File does not exist'
}
")

Bash(powershell -Command "
\\$gradleHome = [System.IO.Path]::Combine\(\\$env:USERPROFILE, '.gradle'\)
\\$daemonDir = [System.IO.Path]::Combine\(\\$gradleHome, 'daemon'\)
if \(Test-Path \\$daemonDir\) {
    Remove-Item \\$daemonDir -Recurse -Force
    Write-Host 'Daemon cache cleared'
} else {
    Write-Host 'No daemon dir found'
}
")

Bash(powershell -Command "
\\$cacheDir = [System.IO.Path]::Combine\(\\$env:USERPROFILE, '.gradle', 'caches', '8.14.4'\)
if \(Test-Path \\$cacheDir\) {
    \\$items = Get-ChildItem \\$cacheDir
    Write-Host 'Cache dir contents:'
    \\$items | Select-Object Name | Format-Table
} else {
    Write-Host 'Cache dir not found'
}
")

Bash(powershell -Command "
\\$workerMainDir = [System.IO.Path]::Combine\(\\$env:USERPROFILE, '.gradle', 'caches', '8.14.4', 'workerMain'\)
if \(Test-Path \\$workerMainDir\) {
