Bash(powershell -Command "
\\$jar = [System.IO.Path]::Combine\(\\$env:USERPROFILE, '.gradle', 'caches', '8.14.4', 'workerMain', 'gradle-worker.jar'\)
try {
    Add-Type -AssemblyName System.IO.Compression.FileSystem
    \\$zip = [System.IO.Compression.ZipFile]::OpenRead\(\\$jar\)
    \\$entries = \\$zip.Entries | Where-Object { \\$_.Name -eq 'GradleWorkerMain.class' }
    if \(\\$entries\) {
        Write-Host 'GradleWorkerMain.class found in JAR'
    } else {
        Write-Host 'GradleWorkerMain.class NOT found in JAR'
        \\$zip.Entries | Select-Object FullName | Format-Table
    }
    \\$zip.Dispose\(\)
} catch {
    Write-Host 'Error reading JAR: ' + \\$_.Exception.Message
}
")

